mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_pdf
    WHERE pdf_id = #{pdfId}
)

SELECT EXISTS (
    SELECT 1
    FROM tb_pdf
    WHERE pdf_id = #{pdfId}
      AND reg_user_id = #{userId}
)

SELECT EXISTS (
    SELECT 1
    FROM tb_pdf
    WHERE drive_file_id = #{driveFileId}
)

SELECT EXISTS (
    SELECT 1
    FROM tb_pdf
    WHERE pdf_id = #{pdfId}
      AND drive_file_id = #{driveFileId}
)

SELECT EXISTS (
    SELECT 1
    FROM tb_comment c
    JOIN tb_pdf p ON p.pdf_id = c.pdf_id
    WHERE c.comment_id = #{commentId}
)

SELECT EXISTS (
    SELECT 1
    FROM tb_comment c
    JOIN tb_pdf p ON p.pdf_id = c.pdf_id
    WHERE c.comment_id = #{commentId}
      AND c.pdf_id = #{pdfId}
)

mapper.update:
UPDATE tb_pdf
SET file_name = #{fileName}
WHERE pdf_id = #{pdfId}

UPDATE tb_pdf
SET file_name = #{fileName},
    file_path = #{filePath}
WHERE pdf_id = #{pdfId}
